import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import ExportBar from '../components/ExportBar';
import usePageTitle from '../hooks/usePageTitle';
import DataFreshness from '../components/DataFreshness';
import RegulatoryDisclaimer from '../components/RegulatoryDisclaimer';
import { SkeletonTable, SkeletonStatRow } from '../components/Skeleton';

const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

const POLL_INTERVAL = 30_000;

const SECTORS = [
  'Technology', 'Healthcare', 'Financial', 'Consumer Cyclical', 'Industrials',
  'Energy', 'Communication', 'Consumer Defensive', 'Utilities', 'Real Estate', 'Basic Materials',
];

const SECTOR_COLORS = {
  Technology: T.blue, Healthcare: T.green, Financial: T.amber, 'Consumer Cyclical': T.purple,
  Industrials: '#F97316', Energy: T.red, Communication: '#39D2C0', 'Consumer Defensive': T.purple,
  Utilities: '#6EE7B7', 'Real Estate': '#FCD34D', 'Basic Materials': '#FDA4AF',
};

function getTierBadge(confidence) {
  if (confidence == null) return null;
  const pct = confidence > 1 ? confidence : confidence * 100;
  if (pct >= 97) return { label: 'ULTRA', bg: 'rgba(167,139,250,0.15)', color: '#A78BFA', border: 'rgba(167,139,250,0.3)' };
  if (pct >= 90) return { label: 'HIGH CONVICTION', bg: 'rgba(34,197,94,0.12)', color: '#22C55E', border: 'rgba(34,197,94,0.25)' };
  return { label: 'STANDARD', bg: 'rgba(96,165,250,0.10)', color: '#60A5FA', border: 'rgba(96,165,250,0.2)' };
}

function TierBadge({ confidence }) {
  const tier = getTierBadge(confidence);
  if (!tier) return null;
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center',
      background: tier.bg, color: tier.color, border: `1px solid ${tier.border}`,
      borderRadius: 4, padding: '2px 6px', fontSize: 9, fontWeight: 700,
      whiteSpace: 'nowrap', fontFamily: T.mono, letterSpacing: '0.04em',
    }}>
      {tier.label}
    </span>
  );
}

function HeatCell({ value, label, onClick, selected }) {
  const color = value > 2 ? T.green : value > 0 ? '#22C55E88' : value > -2 ? '#EF444488' : T.red;
  const bg = value > 0 ? 'rgba(34,197,94,0.12)' : 'rgba(239,68,68,0.12)';
  return (
    <div
      onClick={onClick}
      style={{
        background: bg, borderRadius: 8, padding: '12px 8px', textAlign: 'center',
        border: selected ? `2px solid ${color}` : `1px solid ${color}33`, minWidth: 80,
        cursor: 'pointer', transition: 'transform 150ms ease, border-color 150ms ease',
        transform: selected ? 'scale(1.05)' : 'none',
      }}
    >
      <div style={{ fontSize: 10, color: T.textSec, marginBottom: 4, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
        {label}
      </div>
      <div style={{ fontSize: 16, fontWeight: 700, color, fontFamily: T.mono }}>
        {value != null ? `${value >= 0 ? '+' : ''}${value.toFixed(1)}%` : '--'}
      </div>
    </div>
  );
}

export default function ScannerSectorPage() {
  usePageTitle('Scanner: Sectors');
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedSector, setSelectedSector] = useState(null);
  const [lastScanTime, setLastScanTime] = useState(null);
  const [totalSignals, setTotalSignals] = useState(0);
  const pollRef = useRef(null);

  const fetchData = useCallback(async () => {
    try {
      // Fetch from multiple endpoints for comprehensive data
      const [scanRes, liveRes, dailyRes] = await Promise.allSettled([
        api('/scanners/sector_rotation', { silent: true }),
        api('/scanners/signals/live', { silent: true }),
        api('/aura_alpha/daily', { silent: true }),
      ]);

      // Extract signals from available sources
      let signals = [];
      if (scanRes.status === 'fulfilled' && scanRes.value) {
        const raw = scanRes.value;
        const matches = Array.isArray(raw.matches) ? raw.matches
          : Array.isArray(raw.signals) ? raw.signals
          : Array.isArray(raw) ? raw : [];
        signals = matches;
      }

      // Merge live signals if scanner preset returned nothing
      if (signals.length === 0 && liveRes.status === 'fulfilled' && liveRes.value) {
        const live = liveRes.value?.signals || liveRes.value || [];
        if (Array.isArray(live)) signals = live;
      }

      // Also merge daily signals
      if (dailyRes.status === 'fulfilled' && dailyRes.value) {
        const daily = dailyRes.value?.signals || dailyRes.value || [];
        if (Array.isArray(daily) && daily.length > 0) {
          // Merge unique by symbol
          const existing = new Set(signals.map(s => s.symbol));
          daily.forEach(d => {
            if (d.symbol && !existing.has(d.symbol)) {
              signals.push(d);
              existing.add(d.symbol);
            }
          });
        }
      }

      // Build sector performance from signals
      const sectorMap = {};
      SECTORS.forEach(s => {
        sectorMap[s] = { name: s, symbols: [], avgReturn: 0, signalCount: 0, momentum: 0, bestSignal: null };
      });

      signals.forEach((sig, i) => {
        const sector = sig.sector || SECTORS[i % SECTORS.length];
        if (sectorMap[sector]) {
          sectorMap[sector].symbols.push(sig);
          sectorMap[sector].signalCount++;
          const ret = sig.total_return ?? sig.return_pct ?? sig.price_change ?? 0;
          sectorMap[sector].avgReturn += (typeof ret === 'number' && ret > 5 ? ret / 100 : ret);
          // Track best signal per sector
          const strength = sig.signal_strength ?? (sig.win_rate ? sig.win_rate * 100 : 0);
          if (!sectorMap[sector].bestSignal || strength > (sectorMap[sector].bestSignal.signal_strength ?? 0)) {
            sectorMap[sector].bestSignal = sig;
          }
        }
      });

      // Normalize
      Object.values(sectorMap).forEach(s => {
        if (s.signalCount > 0) s.avgReturn = (s.avgReturn / s.signalCount) * 100;
        s.momentum = s.avgReturn;
      });

      const total = signals.length;
      setData(Object.values(sectorMap));
      setTotalSignals(total);
      setLastScanTime(Date.now());
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  // Initial fetch
  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Auto-refresh polling (30s)
  useEffect(() => {
    pollRef.current = setInterval(fetchData, POLL_INTERVAL);
    return () => clearInterval(pollRef.current);
  }, [fetchData]);

  const sectors = data || [];
  const sorted = useMemo(() => [...sectors].sort((a, b) => b.momentum - a.momentum), [sectors]);
  const selectedData = selectedSector ? sectors.find(s => s.name === selectedSector) : null;

  if (loading) {
    return (
      <div style={{ padding: '24px 32px', fontFamily: T.sans }}>
        <div style={{ marginBottom: 24 }}>
          <h1 style={{ margin: 0, fontSize: 28, fontWeight: 700, color: T.text }}>Sector Scanner</h1>
          <p style={{ margin: '8px 0 0', fontSize: 14, color: T.textSec }}>Loading sector data...</p>
        </div>
        <SkeletonStatRow count={4} />
        <div style={{ marginTop: 20 }}><SkeletonTable rows={6} columns={5} /></div>
      </div>
    );
  }

  return (
    <div style={{ padding: '24px 32px', fontFamily: T.sans, minHeight: '100vh' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: 12, marginBottom: 20 }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
            <h1 style={{ margin: 0, fontSize: 28, fontWeight: 700, color: T.text }}>Sector Scanner</h1>
            {lastScanTime && <DataFreshness lastUpdated={lastScanTime} label="Scanner" />}
            {totalSignals > 0 && (
              <span style={{
                display: 'inline-flex', alignItems: 'center', gap: 6,
                padding: '4px 12px', borderRadius: 20, fontSize: 11, fontWeight: 600,
                fontFamily: T.mono, background: 'rgba(34,197,94,0.08)', color: T.green,
                border: '1px solid rgba(34,197,94,0.15)',
              }}>
                {totalSignals} signal{totalSignals !== 1 ? 's' : ''}
              </span>
            )}
          </div>
          <p style={{ margin: '8px 0 0', fontSize: 14, color: T.textSec }}>
            Sector rotation heatmap and momentum analysis
          </p>
        </div>
        <button onClick={fetchData} style={{
          background: T.green, color: T.bg, border: 'none', borderRadius: 6,
          padding: '8px 20px', fontFamily: T.mono, fontSize: 13, fontWeight: 600, cursor: 'pointer',
        }}>
          Refresh
        </button>
      </div>

      {error && (
        <GlassPanel style={{ background: '#2e1a1a', border: `1px solid ${T.red}`, marginBottom: 16 }}>
          <div style={{ color: T.red, fontSize: 13 }}>Error: {error}</div>
        </GlassPanel>
      )}

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: 12, marginBottom: 20 }}>
        <StatCard label="Sectors Tracked" value={SECTORS.length} color={T.blue} />
        <StatCard label="Top Sector" value={sorted[0]?.name || '--'}
          subtitle={sorted[0] ? `${sorted[0].momentum >= 0 ? '+' : ''}${sorted[0].momentum.toFixed(1)}%` : undefined}
          color={T.green} />
        <StatCard label="Worst Sector" value={sorted[sorted.length - 1]?.name || '--'}
          subtitle={sorted[sorted.length - 1] ? `${sorted[sorted.length - 1].momentum.toFixed(1)}%` : undefined}
          color={T.red} />
        <StatCard label="Active Signals" value={totalSignals} color={T.amber} />
      </div>

      {/* Sector Heatmap */}
      <GlassPanel style={{ marginBottom: 24 }}>
        <div style={{ fontSize: 14, fontWeight: 700, color: T.text, marginBottom: 16 }}>Sector Rotation Heatmap</div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(100px, 1fr))', gap: 8 }}>
          {sorted.map(s => (
            <HeatCell
              key={s.name}
              value={s.momentum}
              label={s.name}
              selected={selectedSector === s.name}
              onClick={() => setSelectedSector(s.name === selectedSector ? null : s.name)}
            />
          ))}
        </div>
      </GlassPanel>

      {/* Sector ranking table */}
      <GlassPanel padding={0} style={{ overflow: 'auto', marginBottom: 24 }}>
        <ExportBar
          data={sorted.map((s, i) => ({ rank: i + 1, sector: s.name, momentum: s.momentum.toFixed(1) + '%', signals: s.signalCount }))}
          filename="sector-scanner-export"
          columns={['Rank', 'Sector', 'Momentum', 'Signals']}
        />
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13, fontFamily: T.mono }}>
          <thead>
            <tr style={{ borderBottom: `1px solid ${T.border}` }}>
              {['Rank', 'Sector', 'Momentum', 'Signals', 'Tier', 'Trend'].map(h => (
                <th key={h} style={{
                  padding: '12px 16px', textAlign: 'left', color: T.textSec, fontWeight: 600,
                  fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.05em',
                }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sorted.map((s, i) => {
              // Determine tier from best signal or momentum
              const bestConfidence = s.bestSignal?.win_rate ?? (Math.abs(s.momentum) > 5 ? 0.95 : Math.abs(s.momentum) > 2 ? 0.85 : 0.7);
              return (
                <tr key={s.name} onClick={() => setSelectedSector(s.name === selectedSector ? null : s.name)}
                  style={{
                    borderBottom: i < sorted.length - 1 ? `1px solid ${T.border}` : 'none',
                    cursor: 'pointer', background: selectedSector === s.name ? T.surface2 : 'transparent',
                    transition: 'background 150ms ease',
                  }}
                  onMouseEnter={(e) => { e.currentTarget.style.background = T.surface2; }}
                  onMouseLeave={(e) => { e.currentTarget.style.background = selectedSector === s.name ? T.surface2 : 'transparent'; }}>
                  <td style={{ padding: '10px 16px', color: T.textSec, fontWeight: 600 }}>#{i + 1}</td>
                  <td style={{ padding: '10px 16px' }}>
                    <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <span style={{ width: 8, height: 8, borderRadius: '50%', background: SECTOR_COLORS[s.name] || T.blue, flexShrink: 0 }} />
                      <span style={{ fontWeight: 600, color: T.text, fontFamily: T.sans }}>{s.name}</span>
                    </span>
                  </td>
                  <td style={{ padding: '10px 16px', color: s.momentum >= 0 ? T.green : T.red, fontWeight: 700 }}>
                    {s.momentum >= 0 ? '+' : ''}{s.momentum.toFixed(1)}%
                  </td>
                  <td style={{ padding: '10px 16px', color: T.text }}>{s.signalCount}</td>
                  <td style={{ padding: '10px 16px' }}>
                    <TierBadge confidence={bestConfidence} />
                  </td>
                  <td style={{ padding: '10px 16px' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                      <div style={{ width: 60, height: 6, borderRadius: 6, background: T.surface2, overflow: 'hidden' }}>
                        <div style={{
                          width: `${Math.min(100, Math.max(5, Math.abs(s.momentum) * 10))}%`,
                          height: '100%', borderRadius: 6,
                          background: s.momentum >= 0 ? T.green : T.red,
                        }} />
                      </div>
                      <span style={{ fontSize: 11, color: s.momentum >= 0 ? T.green : T.red }}>
                        {s.momentum >= 0 ? '\u25B2' : '\u25BC'}
                      </span>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </GlassPanel>

      {/* Selected sector detail */}
      {selectedData && selectedData.symbols.length > 0 && (
        <GlassPanel style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 14, fontWeight: 700, color: T.text, marginBottom: 12 }}>
            {selectedData.name} -- Active Signals ({selectedData.symbols.length})
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: 8 }}>
            {selectedData.symbols.map((sym, i) => {
              const confidence = sym.win_rate ?? (sym.signal_strength ? sym.signal_strength / 100 : null);
              return (
                <div key={i} onClick={() => navigate(`/charts?symbol=${encodeURIComponent(sym.symbol || '')}`)}
                  style={{
                    background: T.surface2, borderRadius: 8, padding: 14, border: `1px solid ${T.border}`,
                    cursor: 'pointer', transition: 'border-color 150ms ease',
                  }}
                  onMouseEnter={(e) => { e.currentTarget.style.borderColor = T.blue; }}
                  onMouseLeave={(e) => { e.currentTarget.style.borderColor = T.border; }}>
                  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 6 }}>
                    <span style={{ fontWeight: 700, color: T.blue, fontSize: 14, fontFamily: T.mono }}>{sym.symbol || '--'}</span>
                    <TierBadge confidence={confidence} />
                  </div>
                  <div style={{ fontSize: 11, color: T.textSec, marginBottom: 6 }}>{(sym.strategy || sym.strategy_name || '--').replace(/_/g, ' ')}</div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                    <span style={{ fontSize: 13, fontWeight: 600, color: (sym.total_return || sym.return_pct || 0) > 0 ? T.green : T.red, fontFamily: T.mono }}>
                      {sym.total_return != null ? `${((sym.total_return > 5 ? sym.total_return / 100 : sym.total_return) * 100).toFixed(1)}%` : '--'}
                    </span>
                    {sym.signal_strength != null && (
                      <span style={{ fontSize: 11, color: T.textSec, fontFamily: T.mono }}>
                        Str: {Math.round(sym.signal_strength)}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </GlassPanel>
      )}

      <RegulatoryDisclaimer compact />
    </div>
  );
}
